import React from 'react';
import styles from '../voucher/VoucherFormStatusGroup.module.css';

export interface DocumentProcessingLevelPillProps {
  label: string;
  compact?: boolean;
  testId?: string;
}

/** Pill mức xử lý — giá thành, khấu hao (parity `VoucherFormStatusGroup`). */
export const DocumentProcessingLevelPill: React.FC<DocumentProcessingLevelPillProps> = ({
  label,
  compact = false,
  testId,
}) => {
  const text = label?.trim();
  if (!text || text === '—') return null;

  return (
    <span
      className={`${styles.levelPill} ${compact ? styles.levelPillCompact : ''}`}
      data-testid={testId}
    >
      {text}
    </span>
  );
};
